def read_local_context(base_dir: str, requested_path: str, file_map: dict[str, str]) -> str:
    def normalize_path(base: str, path: str) -> str:
        # Split the base and path into components
        base_components = base.split('/')
        path_components = path.split('/')

        # Normalize the path components
        stack = []
        for component in path_components:
            if component == '' or component == '.':
                continue
            elif component == '..':
                if stack:
                    stack.pop()
            else:
                stack.append(component)

        # Join the normalized components
        normalized_path = '/'.join(stack)
        return normalized_path

    # Normalize the base directory and requested path
    normalized_base = normalize_path('', base_dir)
    normalized_requested = normalize_path(normalized_base, requested_path)

    # Check if the normalized path is within the base directory
    if not normalized_requested.startswith(normalized_base):
        return "Error: Path traversal detected or path is outside the base directory."

    # Check if the path ends with .txt
    if not normalized_requested.endswith('.txt'):
        return "Error: Only .txt files are allowed."

    # Check if the path is absolute
    if requested_path.startswith('/'):
        return "Error: Absolute paths are not allowed."

    # Attempt to read the file from the file_map
    if normalized_requested in file_map:
        return file_map[normalized_requested]
    else:
        return "Error: File not found."

